import React from "react";

const CATEGORY_COLORS = {
  Food: "bg-orange-100 text-orange-700",
  Travel: "bg-blue-100 text-blue-700",
  Shopping: "bg-pink-100 text-pink-700",
  Education: "bg-purple-100 text-purple-700",
  Health: "bg-green-100 text-green-700",
  Entertainment: "bg-yellow-100 text-yellow-700",
  Other: "bg-gray-100 text-gray-700",
};

export default function ExpenseList({ expenses, onEdit, onDelete }) {
  if (expenses.length === 0) {
    return (
      <div className="bg-white rounded-xl border border-gray-200 p-12 text-center">
        <div className="text-4xl mb-3">🧾</div>
        <p className="text-gray-500">No expenses found. Add your first expense!</p>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
      <div className="px-5 py-3 border-b border-gray-100">
        <h2 className="font-semibold text-gray-700">All Expenses</h2>
      </div>
      <div className="divide-y divide-gray-100">
        {expenses.map((e) => (
          <div key={e.id} className="px-5 py-4 flex items-center justify-between hover:bg-gray-50">
            <div className="flex items-center gap-3">
              <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${CATEGORY_COLORS[e.category] || "bg-gray-100 text-gray-700"}`}>
                {e.category}
              </span>
              <div>
                <p className="font-medium text-gray-800 text-sm">{e.title}</p>
                {e.description && <p className="text-xs text-gray-400">{e.description}</p>}
                <p className="text-xs text-gray-400">{new Date(e.date).toLocaleDateString("en-IN")}</p>
              </div>
            </div>
            <div className="flex items-center gap-4">
              <span className="font-bold text-gray-800">₹{e.amount.toLocaleString("en-IN")}</span>
              <button onClick={() => onEdit(e)} className="text-xs text-indigo-500 hover:underline">Edit</button>
              <button onClick={() => onDelete(e.id)} className="text-xs text-red-400 hover:underline">Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
